# app/helpers/posts_helper.rb

module PostsHelper
  # Custom sanitizer for even more control
  ALLOWED_TAGS = %w[
    p br h1 h2 h3 h4 h5 h6
    strong em b i u s strike
    a img
    ul ol li
    blockquote pre code
    hr div span
    table thead tbody tfoot tr th td
    figure figcaption
    sup sub
  ].freeze

  ALLOWED_ATTRIBUTES = %w[
    href src alt title class id
    target rel width height
    colspan rowspan
  ].freeze

  def safe_post_content(content)
    sanitize(content, tags: ALLOWED_TAGS, attributes: ALLOWED_ATTRIBUTES)
  end

  # Optional: Use a scrubber for advanced filtering
  # e.g., rewrite all links to include rel="nofollow noopener"
  def safe_post_content_with_link_safety(content)
    scrubber = Loofah::Scrubber.new do |node|
      if node.name == "a"
        node["rel"] = "nofollow noopener noreferrer"
        node["target"] = "_blank"
        # Remove javascript: URLs
        if node["href"]&.match?(/\Ajavascript:/i)
          node.remove
        end
      end

      if node.name == "img"
        # Only allow http/https image sources
        unless node["src"]&.match?(/\Ahttps?:\/\//i)
          node.remove
        end
      end
    end

    sanitize(content, scrubber: scrubber)
  end
end